// Reduce the search fan-out to a supply/price snapshot; diff vs the last run.
const inputs = $('Set Inputs').first().json;
const staticData = $getWorkflowStaticData('global');
const rows = [];
for (const item of $input.all()) {
  const data = Array.isArray(item.json.data) ? item.json.data : [];
  for (const p of data) rows.push(p);
}
const totals = rows
  .map((p) => (p.price ? p.price.totalPrice : null))
  .filter((n) => typeof n === 'number')
  .sort((a, b) => a - b);
const supply = rows.length;
const median = totals.length ? totals[Math.floor((totals.length - 1) / 2)] : null;
const cheapest = totals.length ? totals[0] : null;
const bell = rows.find((p) => p.name) || rows[0] || null;
const prevSupply = typeof staticData.lastSupply === 'number' ? staticData.lastSupply : null;
const prevMedian = typeof staticData.lastMedian === 'number' ? staticData.lastMedian : null;
staticData.lastSupply = supply;
staticData.lastMedian = median;
const supplyDropPct =
  prevSupply && prevSupply > 0 ? Math.round(((prevSupply - supply) / prevSupply) * 1000) / 10 : null;
const priceRisePct =
  prevMedian && median ? Math.round(((median - prevMedian) / prevMedian) * 1000) / 10 : null;
return [
  {
    json: {
      supply,
      median,
      cheapest,
      prevSupply,
      prevMedian,
      supplyDropPct,
      priceRisePct,
      bellwetherName: bell && bell.name ? bell.name : null,
      bellwetherCity: (bell && bell.location && bell.location.city) || inputs.location || null,
      bellwetherPlatform: bell ? bell.platform : null,
      bellwetherListingId: bell ? bell.platformListingId : null,
      currency: inputs.currency || (rows[0] && rows[0].price && rows[0].price.currency) || 'USD',
    },
  },
];

// Build the event-radar alert; fire only on tightening supply or rising prices.
const inputs = $('Set Inputs').first().json;
const snap = $('Demand snapshot').first().json;
const availData = ($('Bellwether availability').all()[0] || {}).json || {};
const avail = Array.isArray(availData.data) ? availData.data : [];
const bookableDays = avail.reduce(
  (n, l) => n + (l.dates || []).filter((d) => d.available && d.bookable !== false).length,
  0,
);
const pc = ($input.first() && $input.first().json && $input.first().json.data) || {};
const currency = snap.currency || 'USD';
const supplyDrop = Number(inputs.supplyDropPct) > 0 ? Number(inputs.supplyDropPct) : 20;
const priceRise = Number(inputs.priceRisePct) > 0 ? Number(inputs.priceRisePct) : 10;
const tightening = snap.supplyDropPct != null && snap.supplyDropPct >= supplyDrop;
const rising = snap.priceRisePct != null && snap.priceRisePct >= priceRise;
if (!tightening && !rising) return [];
const supplyLine =
  'Supply: ' + snap.supply + ' listings' +
  (snap.supplyDropPct != null ? ' (' + (snap.supplyDropPct >= 0 ? '-' : '+') + Math.abs(snap.supplyDropPct) + '% vs last run)' : '');
const priceLine =
  'Median: ' + (snap.median != null ? snap.median : '?') + ' ' + currency +
  (snap.priceRisePct != null ? ' (' + (snap.priceRisePct >= 0 ? '+' : '') + snap.priceRisePct + '% vs last run)' : '');
const bellLine = snap.bellwetherName
  ? 'Bellwether "' + snap.bellwetherName + '": ' + bookableDays + ' bookable days · cross-OTA min ' +
    (pc.min != null ? pc.min : '?') + ' / median ' + (pc.median != null ? pc.median : '?') + ' ' + (pc.currency || currency)
  : '';
const message =
  ':rotating_light: Event demand radar — ' + (inputs.eventName || inputs.location) + '\n' +
  supplyLine + '\n' + priceLine + '\n' + 'Cheapest now: ' + (snap.cheapest != null ? snap.cheapest : '?') + ' ' + currency + '\n' +
  (bellLine ? bellLine + '\n' : '') +
  (tightening ? 'Supply is tightening — a pricing opportunity.\n' : '') +
  (rising ? 'Prices are rising — consider adjusting rates.\n' : '');
return [{ json: { supply: snap.supply, median: snap.median, cheapest: snap.cheapest, tightening, rising, bookableDays, report: message } }];
